const LOGO_COLOR = "data:image/png;base64,";

const fontDisplay = { fontFamily: "var(--font-display)", fontWeight: 700 };
const fontBody = { fontFamily: "var(--font-body)" };
const fontMono = { fontFamily: "var(--font-mono)" };
const fs = (n) => ({ fontSize: n });

function useGoogleFonts() {
  useEffect(() => {
    if (document.getElementById("redbook-fonts")) return;
    const link = document.createElement("link");
    link.id = "redbook-fonts";
    link.rel = "stylesheet";
    link.href =
      "https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600&family=Noto+Kufi+Arabic:wght@400;500;600;700&display=swap";
    document.head.appendChild(link);
  }, []);
}

function fmtEGP(n) {
  if (n >= 1000000) return `${(n / 1000000).toFixed(2)}M`;
  if (n >= 1000) return `${Math.round(n / 1000)}K`;
  return `${Math.round(n)}`;
}
function pointsForValue(egp) { return Math.round((egp / 1000000) * 2000); }

