function ScreenHeader({ eyebrow, title, right }) {
  return (
    <div className="px-5 pt-4 pb-3 flex items-start justify-between">
      <div>
        {eyebrow && <div className="tracking-widest uppercase mb-1" style={{ ...fontMono, ...fs(11), color: RED }}>{eyebrow}</div>}
        <h1 style={{ ...fontDisplay, ...fs(21), color: INK }}>{title}</h1>
      </div>
      {right}
    </div>
  );
}

function TierRing({ value, floor, ceiling, size = 104 }) {
  const pct = Math.min(1, Math.max(0, (value - floor) / (ceiling - floor)));
  const r = (size - 14) / 2;
  const c = 2 * Math.PI * r;
  const { tr } = useT();
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke={LINE} strokeWidth="10" />
      <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke={RED} strokeWidth="10" strokeLinecap="round"
        strokeDasharray={c} strokeDashoffset={c * (1 - pct)} transform={`rotate(-90 ${size / 2} ${size / 2})`} />
      <text x="50%" y="46%" textAnchor="middle" style={{ ...fontDisplay, fontSize: 20, fill: INK }}>{(value / 1000).toFixed(1)}k</text>
      <text x="50%" y="62%" textAnchor="middle" style={{ ...fontMono, fontSize: 9, fill: GREY, letterSpacing: "0.06em" }}>{tr("rewards").toUpperCase()}</text>
    </svg>
  );
}

function Badge({ children, tone = "dark" }) {
  const styles = tone === "dark" ? { background: INK, color: "#fff" }
    : tone === "red" ? { background: RED, color: "#fff" }
    : tone === "good" ? { background: "#eaf3ec", color: GOOD }
    : tone === "amber" ? { background: "#fbf1e2", color: AMBER }
    : { background: PAPER, color: INK, border: `1px solid ${LINE}` };
  return (
    <span className="inline-flex items-center gap-1 px-2.5 py-1 rounded-full whitespace-nowrap" style={{ ...fontMono, ...fs(10.5), fontWeight: 500, ...styles }}>
      {children}
    </span>
  );
}

function SegControl({ options, value, onChange }) {
  return (
    <div className="flex gap-1.5 overflow-x-auto pb-0.5" style={{ scrollbarWidth: "none" }}>
      {options.map((o) => (
        <button key={o.id} onClick={() => onChange(o.id)} className="px-3.5 py-2 rounded-full flex-shrink-0"
          style={{ ...fontMono, ...fs(12), fontWeight: 500, background: value === o.id ? INK : CARD, color: value === o.id ? "#fff" : GREY, border: `1px solid ${value === o.id ? INK : LINE}` }}>
          {o.label}
        </button>
      ))}
    </div>
  );
}

function useStages() {
  const { tr } = useT();
  return [
    { id: "reservation", label: tr("stageReservation"), actor: tr("actorBroker") },
    { id: "contracted", label: tr("stageContracted"), actor: tr("actorBroker") },
    { id: "confirmed", label: tr("stageConfirmed"), actor: tr("actorDevAndRedBook") },
  ];
}
function stageIndex(stages, stage) {
  if (stage === "cancelled") return -1;
  const direct = stages.findIndex((s) => s.id === stage);
  if (direct >= 0) return direct;
  if (["developer_review", "developer_approved", "verified", "eligible", "payout_requested", "paid"].includes(stage)) return stages.length - 1;
  return 0;
}

function StageStepper({ stage, compact }) {
  const stages = useStages();
  const idx = stageIndex(stages, stage);
  if (stage === "cancelled") return <Badge tone="red">Cancelled</Badge>;
  return (
    <div className="flex items-center">
      {stages.map((s, i) => (
        <React.Fragment key={s.id}>
          <div className="flex flex-col items-center flex-shrink-0" style={{ width: compact ? 54 : 78 }}>
            <div className="rounded-full flex items-center justify-center flex-shrink-0"
              style={{ width: compact ? 18 : 22, height: compact ? 18 : 22, background: i <= idx ? (i < idx ? GOOD : RED) : "#fff", border: `2px solid ${i <= idx ? (i < idx ? GOOD : RED) : LINE}` }}>
              {i < idx ? <Check size={compact ? 10 : 12} color="#fff" strokeWidth={3} /> : <span style={{ ...fontMono, fontSize: compact ? 8 : 9, color: i <= idx ? "#fff" : GREY }}>{i + 1}</span>}
            </div>
            {!compact && (
              <>
                <div className="mt-1 text-center leading-tight" style={{ ...fontMono, fontSize: 9.5, color: i <= idx ? INK : GREY, fontWeight: i === idx ? 600 : 400 }}>{s.label}</div>
                <div className="text-center" style={{ ...fontMono, fontSize: 8, color: GREY }}>{s.actor}</div>
              </>
            )}
          </div>
          {i < stages.length - 1 && <div className="flex-1" style={{ height: 2, background: i < idx ? GOOD : LINE, marginBottom: compact ? 0 : 16 }} />}
        </React.Fragment>
      ))}
    </div>
  );
}

